import{_ as t,o as r,c as e,ag as s}from"./chunks/framework.WmBmIPw-.js";const d=JSON.parse('{"title":"禁忌搜索（Tabu Search, TS）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/tabu-search.md","filePath":"or-opt/tabu-search.md","lastUpdated":1777121120000}'),o={name:"or-opt/tabu-search.md"};function i(n,a,l,h,p,c){return r(),e("div",null,[...a[0]||(a[0]=[s('<h1 id="禁忌搜索-tabu-search-ts" tabindex="-1">禁忌搜索（Tabu Search, TS） <a class="header-anchor" href="#禁忌搜索-tabu-search-ts" aria-label="Permalink to &quot;禁忌搜索（Tabu Search, TS）&quot;">​</a></h1><p>禁忌搜索在邻域搜索框架上引入短期记忆，结合渴望准则，在探索与利用之间折中。属单点、带记忆的元启发式，见 <a href="./metaheuristics.html">元启发式总览</a>。</p><p><strong>适用</strong>：组合优化（TSP、调度、图着色等）的近似求解；禁忌属性、tenure 与渴望的设计对效果影响大。</p><p><strong>核心</strong>：在「邻域可行情景」下，用禁忌表延缓对近期已犯移动的立即回退；在禁忌仍封锁优良移动时，用渴望准则破禁。</p><hr><h2 id="算法-最小化示意" tabindex="-1">算法（最小化示意） <a class="header-anchor" href="#算法-最小化示意" aria-label="Permalink to &quot;算法（最小化示意）&quot;">​</a></h2><p>以目标函数 f(s) 最小化叙述；与一次移动 m 可关联的属性记为 a（如边、对换对等）。禁忌表在实现上可视为：近期被禁止的属性及其剩余禁忌步数的集合。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 禁忌搜索主循环（单解、邻域 + 禁忌表）</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>选定初始解 s，记历史最优 s⋆ ← s。禁忌结构置空。设定：邻域算子、tenure 或其区间、最大迭代/时间、与渴望相关的参数。</p><h3 id="_2-邻域与筛选" tabindex="-1">2. 邻域与筛选 <a class="header-anchor" href="#_2-邻域与筛选" aria-label="Permalink to &quot;2. 邻域与筛选&quot;">​</a></h3><p>自当前 s 得候选集 N(s)（可采样）。对候选移动 m 得 s′ = m(s)。若 m 的属性 a 仍处禁忌期，则 m 通常不入选，除非满足下文「渴望准则」一节中预先声明的条件。</p><h3 id="_3-选择与移动" tabindex="-1">3. 选择与移动 <a class="header-anchor" href="#_3-选择与移动" aria-label="Permalink to &quot;3. 选择与移动&quot;">​</a></h3><p>在可接受候选中依规则选一步（如：存在改进步则选最优改进；否则选最小增的恶化步）。执行移动，更新 s。</p><h3 id="_4-更新禁忌与全局最优" tabindex="-1">4. 更新禁忌与全局最优 <a class="header-anchor" href="#_4-更新禁忌与全局最优" aria-label="Permalink to &quot;4. 更新禁忌与全局最优&quot;">​</a></h3><p>将本步属性 a 入表，剩余步数置为 tenure（或自区间随机等变体，见下文章节「禁忌表」）。若 f(s) &lt; f(s⋆)，令 s⋆ ← s。</p><h3 id="_5-终止" tabindex="-1">5. 终止 <a class="header-anchor" href="#_5-终止" aria-label="Permalink to &quot;5. 终止&quot;">​</a></h3><p>达迭代/时间/无改进步数等，或触发重启；输出 s⋆。</p></div><hr><h2 id="禁忌表-tabu-list" tabindex="-1">禁忌表（Tabu List） <a class="header-anchor" href="#禁忌表-tabu-list" aria-label="Permalink to &quot;禁忌表（Tabu List）&quot;">​</a></h2><p><strong>对象</strong>：表内通常不直接「禁止解向量本身」（维度过大），而禁止可逆、可标识的移动属性 a；例如 TSP 中「边 (i, j) 刚被删除又立刻加回」、调度中「某工序对在相邻换位」等。同一邻域上属性与移动的抽取规则要一致，否则「禁忌了谁」在实现上会含糊。</p><p><strong>Recency 与 tenure</strong>：表维护的是近若干步内、或每属性剩余禁忌迭代数。</p><ul><li><strong>固定 tenure L</strong>：a 在入选后，连续 L 步内禁止再次出现「由该属性标识的逆移动」或相同属性再选（与邻域如何定义逆有关）。L 过短易短循环，过长易过度排斥合理探索。</li><li><strong>变长 tenure</strong>：在区间 [Lmin, Lmax] 上随机、或随搜索阶段调整，以减轻周期性与参数敏感。</li></ul><p><strong>实现形态</strong>：常采用循环队列/滑动窗口存最近 L 个属性，或每属性一计数每步减一直至 0 解禁；大邻域时可用子集评估候选、不必每次扫描全邻域（与 candidate list 思想衔接）。</p><p><strong>与邻域/逆移</strong>：禁忌针对的是「属性」在文献中有时对应「禁止逆移一定步数」；逆移的定义依赖编码（如 2-opt 的逆操作）。实现前应在问题说明里写清一条移动对应什么属性、逆移动对应何属性对。</p><h2 id="渴望准则-aspiration-criteria" tabindex="-1">渴望准则（Aspiration Criteria） <a class="header-anchor" href="#渴望准则-aspiration-criteria" aria-label="Permalink to &quot;渴望准则（Aspiration Criteria）&quot;">​</a></h2><p><strong>作用</strong>：在移动因禁忌被挡时，若该移动特别有价值，则允许破禁执行。否则禁忌表会机械地挡住全局最优邻域点，渴望避免这一情形。</p><p><strong>经典准则</strong>（最常用）：若候选 s′ 满足 f(s′) &lt; f(s⋆)（带出新历史最优），则允许即使对应移动属性仍在禁忌期也选用该步。这保证「有记录以来最好的解」不会被禁忌机械排除（在邻域能到达的前提下）。</p><p><strong>其他常见变体</strong>（可组合使用、按问题调参）：</p><ul><li><strong>按目标渴望</strong>：f(s′) 优于某一参考阈值（如本阶段最佳、加惩罚后的评价）。</li></ul><p><strong>注</strong>：破禁时仍应更新禁忌表与 s⋆ 的规则与常规步一致，并在日志中区分「渴望步」与「普通过步」便于调参复现。</p>',21)])])}const b=t(o,[["render",i]]);export{d as __pageData,b as default};
